INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-d592fc58-moex-00188', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲贈與Ａ畫給乙，乙允受之。下列敘述，何者正確？', '["贈與物之權利移轉前，或移轉後，甲皆得任意撤銷其贈與", "經公證之贈與，縱使受贈人乙對贈與人甲有故意傷害行為，仍不得撤銷", "乙因故意傷害行為導致贈與人甲死亡，甲之繼承人得於知有撤銷原因之時起，6個月內撤銷贈與", "贈與人於贈與約定後，經濟情況顯有變更，致影響生計時，得撤銷贈與"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00189', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲乙丙三兄弟，因繼承父親之遺產而公同共有A地；甲未經乙丙同意，擅自與丁訂立買賣契約， 將A地賣給丁。下列敘述，何者正確？', '["甲與丁訂立之A地買賣契約有效", "甲丁買賣契約因自始不能，故無效", "甲丁買賣契約經乙丙同意，始有效", "乙丙得撤銷甲丁訂立之買賣契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00190', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲公司是乙公司之經銷商，向乙公司進貨，銷售乙公司之產品；由甲提供A地為乙設定最高限額 新臺幣 1,000 萬元之最高限額抵押權，用以擔保乙對甲因經銷關係所生之債權。下列債權，何者 並非最高限額抵押權所擔保之債權？', '["因甲債務不履行，而乙因此取得對甲之損害賠償債權", "甲因財務困難向乙貸款，乙因此取得對甲之借款返還債權", "甲要求乙將貨物送達清償地以外之處所，乙因此取得對甲之運費債權", "甲為支付貨款簽發票據，乙因此取得之票款債權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00191', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列何者契約，縱經登記，亦不生對抗第三人之物權化效力？', '["共有物之分管契約", "共有物之不分割契約", "房屋租賃契約", "流押（流抵）契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00192', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '以有價證券為質權之標的物者，其附屬於該證券之利息證券、定期金證券或其他附屬證券，依民 法規定，下列何者為質權效力所及？', '["設質前已發行之附屬證券，以已交付於質權人者為限，為質權效力所及", "設質前已發行之附屬證券，無論是否已交付於質權人者，均為質權效力所及", "設質後所發行之附屬證券，以已交付於質權人者為限，為質權效力所及", "設質前後所發行之附屬證券，基於證券交易之原理，無論是否已交付於質權人者，均為質權效 力所及"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00193', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲登記為A地所有人，在A地上設定20年期限之普通地上權於乙。甲與乙約定，乙每年應支付 新臺幣15萬元地租於甲。下列敘述，何者正確？', '["乙得逕行占有A地", "乙得在A地上下為建築物及其他工作物目的外之使用", "乙得讓與A地之地上權於他人", "乙得隨時拋棄其於A地之地上權 13740、40140 41140"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00194', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲為A公司董事長。A公司為B車所有人，以B車為甲之專用座車。A公司僱用乙為司機兼保 鑣，專以B車接送並保護甲，並將B車交付於乙保管。某日，乙以B車接送甲至某公司開會，A 公司所僱用之董事長特助丙，亦在隨行之列。下列敘述，何者正確？', '["甲為B車之占有人", "乙為B車之占有人", "A公司為B車之占有人", "丙為B車之占有人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00195', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列關於夫妻財產制之敘述，何者正確？', '["夫妻應於結婚後，依民法親屬編規定，以契約選擇其一夫妻財產制，並向戶政機關登記，始生 對抗第三人之效力", "夫妻財產制之締結、變更或廢止，應以書面為之，並有2人以上之證人簽名", "夫妻之一方，依法應給付扶養費而不給付時，戶政機關得依他方之申請，將之改登記為分別財 產制", "夫妻難以維持共同生活，不同居已達6個月以上時，法院因他方之請求，得宣告改用分別財產制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00196', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '下列關於親屬間結婚之敘述，何者錯誤？', '["旁系姻親在五親等以內，輩分相同者，不得結婚", "因收養而成立之四親等及六親等旁系血親，輩分相同者，得結婚", "直系姻親不得結婚", "直系血親不得結婚"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
  ('promotion-d592fc58-moex-00197', 'promotion-d592fc58', 'promotion-d592fc58-moex-110-9b7ab1bb', 'sub-promotion-d592fc58-02', NULL, 'single_choice', '甲為乙之母，丙男認領乙。數年後，丙請求乙扶養，關於此事是否有理，可能有幾個因素：①丙', '["丙沒有乙得主張顯失公平請求減免扶養義務之情形", "丙認領乙有效", "丙 無謀生能力  ⑤乙有扶養能力。各因素如依照判斷先後順序排列，下列何者為妥？", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "135", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL)
